config.adaptive_card:
{
  "type": "message",
  "attachments": [
    {
      "contentType": "application/vnd.microsoft.card.adaptive",
      "content": {
        "type": "AdaptiveCard",
        "version": "1.5",
        "msTeams": { "width": "full" },
        "body": [
          {
            "type": "TextBlock",
            "size": "Large",
            "weight": "Bolder",
            "text": "${event_definition_title} triggered",
            "style": "heading",
            "fontType": "Default"
          },
          {
            "type": "TextBlock",
            "text": "${event_definition_description}",
            "wrap": true
          },
          {
            "type": "TextBlock",
            "text": "Event Details",
            "wrap": true
          },
          {
            "type": "FactSet",
            "facts": [
              {
                "title": "Type",
                "value": "${event_definition_type}"
              },
              {
                "title": "Timestamp",
                "value": "${event.timestamp_processing}"
              },
              {
                "title": "Message",
                "value": "${event.message}"
              },
              {
                "title": "Source",
                "value": "${event.source}"
              },
              {
                "title": "Key",
                "value": "${event.key}"
              },
              {
                "title": "Priority",
                "value": "${event.priority}"
              },
              {
                "title": "Alert",
                "value": "${event.alert}"
              },
              {
                "title": "Timerange Start",
                "value": "${event.timerange_start}"
              },
              {
                "title": "Timerange End",
                "value": "${event.timerange_end}"
              }
            ]
          }${if event.fields},
          {
            "type": "TextBlock",
            "text": "Event Fields",
            "weight": "bolder",
            "size": "medium"
          },
          {
            "type": "FactSet",
            "facts": [${foreach event.fields field}
              { "title": "${field.key}", "value": "${field.value}" }${if last_field}${else},${end}${end}
            ]
          }${end}${if backlog},
          {
            "type": "TextBlock",
            "text": "Backlog",
            "weight": "bolder",
            "size": "medium"
          },
          {
            "type": "FactSet",
            "facts": [${foreach backlog message}
              { "title": "Message", "value": "${message.message}" }${if last_message}${else},${end}${end}
            ]
          }${end}
        ],
        "actions": [{
          "type": "Action.OpenUrl",
          "title": "Replay Search",
          "url": "${http_external_uri}alerts/${event.id}/replay-search"
        }],
        "$schema": "http://adaptivecards.io/schemas/adaptive-card.json",
        "rtl": false
      }
    }
  ]
}
